module RefModule (
  input CLK,
  input EN,
  input TE,
  output ENCLK
);

  reg obf_gated_clk;

  always @(posedge CLK) begin
    if (EN && !TE) begin
      obf_gated_clk <= 1'b1;
    end else begin
      obf_gated_clk <= 1'b0;
    end
  end

  assign ENCLK = obf_gated_clk & CLK;

endmodule
